import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"噬目","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/3.瞳术/噬目.md","filePath":"4.资源分区/3.瞳术/噬目.md"}'),d={name:"4.资源分区/3.瞳术/噬目.md"};function p(l,a,i,_,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"噬目",tabindex:"-1"},[s("噬目 "),e("a",{class:"header-anchor",href:"#噬目","aria-label":'Permalink to "噬目"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风027")])])],-1),o('<h1 id="噬目-1" tabindex="-1">噬目 <a class="header-anchor" href="#噬目-1" aria-label="Permalink to &quot;噬目&quot;">​</a></h1><p>噬目<br> C+1200<br> “这是这次的佣金”<br> “那个独眼的家伙很强……”<br> 这是他这辈子听到和交流最多的两句话，但他只知道那场战斗让他付出了一只眼睛，而战斗的结果并不尽人意。在经过一次意志的洗礼后……他才变成现在这副模样。<br> 他再一次看向了镜子内的自己，眼眶下不再是空洞的黑暗，而是由能量凝聚的眼睛或者说只是一个带着光效的能量球，举手投足之间除了有些绚丽的能量尾迹之外没有什么效果，甚至不能视物，但却让他更加渴望战斗了。</p><p>强化该瞳术后，在你没有吞下自身的左眼之前，该瞳术不会提供任何效果。</p><p>【源目】当你吞下自身的左眼之后，这个瞳术开始激活，或者说意志洗礼的到来。<br> 首先你无法再用任何方法生长或者替换自身的左眼，你的左眼处会长出一颗类似眼球的能量球，虽然不能视物，但却能使你另一个眼睛免疫强光等效果，你从现在开始免疫目眩的减值以及严重状态。</p><p>【噬】这是意志洗礼的表现……真的是如此吗？没有人知道，因为那场战斗……不，准确来说是献祭，让真正的受益者稳坐高台，而幸存者眼中只剩下复仇的火焰。<br> 你不会因为伤势严重而陷入昏迷，同时，当你生命值降低至自身完好生命值的一半以下时（向下取整），你的近战攻击会吸取敌人的鲜血以此来恢复自身，你近战攻击获得吸血5，持续一个场景。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',7)])])}const m=r(d,[["render",p]]);export{f as __pageData,m as default};
